    ///
    /// ```
    /// use std::thread;
    /// use std::time::Duration;
    /// use crossbeam_channel::unbounded;
    ///
    /// let (s, r) = unbounded::<i32>();
    ///
    /// # let t =
    /// thread::spawn(move || {
    ///     s.send(1).unwrap();
